CREATE TYPE "PermissionEffect" AS ENUM ('ALLOW','DENY');
CREATE TABLE "StaffRoleTemplate" ("id" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"systemRole" BOOLEAN NOT NULL DEFAULT false,"active" BOOLEAN NOT NULL DEFAULT true,"displayOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "StaffRoleTemplate_pkey" PRIMARY KEY ("id"));
CREATE TABLE "StaffPermissionDefinition" ("id" TEXT NOT NULL,"code" TEXT NOT NULL,"module" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"dangerous" BOOLEAN NOT NULL DEFAULT false,"displayOrder" INTEGER NOT NULL DEFAULT 0,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "StaffPermissionDefinition_pkey" PRIMARY KEY ("id"));
CREATE TABLE "StaffRolePermission" ("id" TEXT NOT NULL,"roleId" TEXT NOT NULL,"permissionId" TEXT NOT NULL,CONSTRAINT "StaffRolePermission_pkey" PRIMARY KEY ("id"));
CREATE TABLE "StaffPermissionOverride" ("id" TEXT NOT NULL,"staffUserId" TEXT NOT NULL,"permissionId" TEXT NOT NULL,"effect" "PermissionEffect" NOT NULL,"reason" TEXT,"assignedByStaffId" TEXT,"assignedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "StaffPermissionOverride_pkey" PRIMARY KEY ("id"));
ALTER TABLE "StaffUser" ADD COLUMN "staffCode" TEXT,ADD COLUMN "department" TEXT,ADD COLUMN "jobTitle" TEXT,ADD COLUMN "roleTemplateId" TEXT,ADD COLUMN "isSystemOwner" BOOLEAN NOT NULL DEFAULT false,ADD COLUMN "lastLoginAt" TIMESTAMP(3),ADD COLUMN "disabledAt" TIMESTAMP(3);
CREATE UNIQUE INDEX "StaffRoleTemplate_code_key" ON "StaffRoleTemplate"("code");CREATE UNIQUE INDEX "StaffPermissionDefinition_code_key" ON "StaffPermissionDefinition"("code");CREATE INDEX "StaffPermissionDefinition_module_displayOrder_idx" ON "StaffPermissionDefinition"("module","displayOrder");CREATE UNIQUE INDEX "StaffRolePermission_roleId_permissionId_key" ON "StaffRolePermission"("roleId","permissionId");CREATE INDEX "StaffRolePermission_permissionId_idx" ON "StaffRolePermission"("permissionId");CREATE UNIQUE INDEX "StaffPermissionOverride_staffUserId_permissionId_key" ON "StaffPermissionOverride"("staffUserId","permissionId");CREATE INDEX "StaffPermissionOverride_effect_idx" ON "StaffPermissionOverride"("effect");CREATE UNIQUE INDEX "StaffUser_staffCode_key" ON "StaffUser"("staffCode");
ALTER TABLE "StaffUser" ADD CONSTRAINT "StaffUser_roleTemplateId_fkey" FOREIGN KEY ("roleTemplateId") REFERENCES "StaffRoleTemplate"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "StaffRolePermission" ADD CONSTRAINT "StaffRolePermission_roleId_fkey" FOREIGN KEY ("roleId") REFERENCES "StaffRoleTemplate"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "StaffRolePermission" ADD CONSTRAINT "StaffRolePermission_permissionId_fkey" FOREIGN KEY ("permissionId") REFERENCES "StaffPermissionDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "StaffPermissionOverride" ADD CONSTRAINT "StaffPermissionOverride_staffUserId_fkey" FOREIGN KEY ("staffUserId") REFERENCES "StaffUser"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "StaffPermissionOverride" ADD CONSTRAINT "StaffPermissionOverride_permissionId_fkey" FOREIGN KEY ("permissionId") REFERENCES "StaffPermissionDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE;
